Hi,

I'm trying to get the trusted_auth_header to work but the setup is failing. I'm running wsgidav behind an nginx that exposes the authenticated LDAP user as follows:

    [...]
    server {
            # SSL configuration
            server_name webdav.sld.tld;
    
            listen 443 ssl http2;
            listen [::]:443 ssl http2;
    
            include snippets/ssl-our.dyndns.ws.conf;
            include snippets/ssl-params.conf;
    
            root /var/www/html;
    
            # Add index.php to the list if you are using PHP
            index index.html index.htm index.nginx-debian.html;
    
            set $upstream 10.0.3.56:1080;
    
            dav_methods     PUT DELETE MKCOL COPY MOVE;
            dav_ext_methods   PROPFIND OPTIONS;
            create_full_put_path  on;
            dav_access    user:rw group:rw all:rw;
            autoindex     on;
    
            location / {
              ## Require LDAP authentication
              auth_request /auth-proxy;
    
              proxy_pass     http://$upstream;
              proxy_redirect http://$upstream https://$server_name;
    
              proxy_cache off;
              proxy_store off;
              proxy_buffering off;
              proxy_http_version 1.1;
              proxy_read_timeout 36000s;
    
              proxy_set_header Host $http_host;
              proxy_set_header Upgrade $http_upgrade;
              proxy_set_header Connection $connection_upgrade;
              proxy_set_header X-Real-IP $remote_addr;
              proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
              proxy_set_header X-Forwarded-Proto $scheme;
              proxy_set_header X-Forwarded-User $remote_user;
              proxy_set_header Referer "";
    
              client_max_body_size 0;
            }
    
            location ~ /\.ht {
                    deny all;
            }
    
    
            location ~ /.well-known {
                    allow all;
            }
    
            # Pull in ldap authentication snippet
            include app.d/default.auth-proxy.conf;
    }
[...]
    
What I tried so far when it comes to wsgidav.conf is the following:

    provider_mapping = {}
    user_mapping = {}
    def addShare(shareName, davProvider):
        provider_mapping[shareName] = davProvider
    def addUser(realmName, user, password, description, roles=[]):
        realmName = "/" + realmName.strip(r"\/")
        userDict = user_mapping.setdefault(realmName, {}).setdefault(user, {})
        userDict["password"] = password
        userDict["description"] = description
        userDict["roles"] = roles
    port = 1080
    host = "0.0.0.0"
    add_header_MS_Author_Via = True
    verbose = 5          # 0 - quiet
                         # 1 - no output (excepting application exceptions)
                         # 2 - warnings and errors only
                         # 3 - show single line request summaries (HTTP logging)
                         # 4 - show additional events
                         # 5 - show full request/response header info (HTTP Logging)
                         #     request body and GET response bodies not shown
    enable_loggers = [ "http_authenticator" ]
    debug_methods = []
    debug_litmus = []
    dir_browser = {
        "enable": True,               # Render HTML listing for GET requests on collections
        "response_trailer": "",       # Raw HTML code, appended as footer
        "davmount": False,            # Send <dm:mount> response if request URL contains '?davmount'
        "ms_mount": False,            # Add an 'open as webfolder' link (requires Windows)
        "ms_sharepoint_plugin": True, # Invoke MS Offce documents for editing using WebDAV
        "ms_sharepoint_urls": False,  # Prepend 'ms-word:ofe|u|' to URL for MS Offce documents
    }
    propsmanager = True
    addShare("", "/volume0/share")
    trusted_auth_header = "X-Forwarded-User"


