In the C API there are several functions for getting and setting the assorted sensor options. The functions [take a parameter](https://github.com/IntelRealSense/librealsense/blob/master/include/librealsense2/h/rs_option.h#L146) of type `rs2_options`, but there seemingly isn't a way to get a list of such  types in the C API. This type would seem to map to a C++ base class in [rs.cpp:45](https://github.com/IntelRealSense/librealsense/blob/master/src/rs.cpp#L44).

Are we supposed to perform a cast or is this an oversight in the C API? The documentation on those functions suggests the intent was to use `rs2_sensor*`

```
#include <librealsense2/rs.h>
#include <librealsense2/h/rs_option.h>

#include <stdlib.h>
#include <stdint.h>
#include <stdio.h>

uint8_t check_error(rs2_error* e)
{
    if (e)
    {
        fprintf(stderr, "rs_error was raised when calling %s(%s): \n",
               rs2_get_failed_function(e), rs2_get_failed_args(e));
        fprintf(stderr, "%s\n", rs2_get_error_message(e));
        return 1;
    }
    return 0;
}

int main()
{
    rs2_error* e = 0;

    rs2_context* ctx = rs2_create_context(RS2_API_VERSION, &e);
    if (check_error(e) != 0)
        return 1;

    rs2_device_list* device_list = rs2_query_devices(ctx, &e);
    if (check_error(e) != 0)
        return 1;

    int dev_count = rs2_get_device_count(device_list, &e);
    if (check_error(e) != 0)
        return 1;

    printf("There are %d connected RealSense devices.\n", dev_count);
    if (0 == dev_count)
        return 1;

    // Get the first connected device
    // The returned object should be released with rs2_delete_device(...)
    rs2_device* dev = rs2_create_device(device_list, 0, &e);
    if (check_error(e) != 0)
        return 1;

    rs2_sensor_list* slist = rs2_query_sensors(dev, &e);
    if (check_error(e) != 0)
        return 1;

    int sensor_list_count = rs2_get_sensors_count(slist, &e);
    if (check_error(e) != 0)
        return 1;

    for (int sensor_index = 0; sensor_index <sensor_list_count; sensor_index++)
    {
        rs2_sensor* sen = rs2_create_sensor(slist, sensor_index, &e);

        if (check_error(e) != 0) {
            fprintf(stderr, "Failed creating temp sensor object %d / %d\n", sensor_index, sensor_list_count);
            return 1;
        }

        // Scary cast here
        int supports = rs2_supports_option((const rs2_options*)sen, RS2_OPTION_LASER_POWER, &e);
        if (check_error(e) != 0)
            return 1;

        if (supports) {

            float min, max, step, def;
            // Scary cast here
            rs2_get_option_range((const rs2_options*)sen, RS2_OPTION_LASER_POWER, &min, &max, &step, &def, &e);
            if (check_error(e) != 0)
                return 1;

            // Scary cast here
            rs2_set_option((const rs2_options*)sen, RS2_OPTION_LASER_POWER, max, &e);
            if (check_error(e) != 0)
                return 1;
            fprintf(stderr, "Set laser power to: %f\n", max);
        }

        rs2_delete_sensor(sen);
    }

    rs2_delete_sensor_list(slist);
    rs2_delete_device(dev);
    rs2_delete_device_list(device_list);
    rs2_delete_context(ctx);

    return EXIT_SUCCESS;
}
```

Why can't input arguments be marked as required in mutations (and I suppose in the normal schema too)? It seems it's possible if you create a `InputField` to have it be required, but I can't mark primitives as required.

This:
```python
class DoSomething(graphene.Mutation):
    class Input(object):
        param_1 = graphene.String(required=True)

    @classmethod
    @with_context
    def mutate(cls, _, args, context, __):
        pass
```

blows up with `__init__() got an unexpected keyword argument 'required'`.

Is this intended or an oversight?

We are using DjangoFormMutations (#217), and what I'm not sure about is how Django's ID/PKs are resolved in the process. They still appear in base64 encoding in the GraphQL output but in `BaseDjangoFormMutation` method they are processed as is.

The error returned from GraphQL shows that the instance is fetched using the string with the base64 encoded ID instead of the decoded PK integer value.

    "errors": [
      {
        "message": "invalid literal for int() with base 10: 'UHJvamVjdE5vZGU6MTA1'",

I think the following code from /graphene_django/forms/mutation.py should use `from_global_id` instead of the value as is:

    @classmethod
    def get_form_kwargs(cls, root, info, **input):
        kwargs = {'data': input}

        pk = input.pop('id', None)
        if pk:
            instance = cls._meta.model._default_manager.get(pk=pk)
            kwargs['instance'] = instance

        return kwargs

I'm not 100% sure about this. We are using UUIDs next to Django's IDs so I had to extend `get_form_kwargs` anyway, and it works fine that way. But it's not working for ID. If the above is the correct location for the fix I can create a pull request. Just wanted to check back if I'm understanding this correctly.
